               <div className="absolute inset-0 bg-stone-900/60 backdrop-blur-sm"></div>
          </div>

          <motion.div 
            initial={{ opacity: 0, scale: 0.9, y: 50 }} 
            whileInView={{ opacity: 1, scale: 1, y: 0 }} 
