const GlobalSettingsView = () => {
    const { companyInfo, updateCompanyInfo, showToast } = useData();
    const [localInfo, setLocalInfo] = useState<CompanyInfo>(companyInfo);
    const [isSaving, setIsSaving] = useState(false);

    useEffect(() => {
        setLocalInfo(companyInfo);
    }, [companyInfo]);

    const hasChanges = JSON.stringify(localInfo) !== JSON.stringify(companyInfo);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const { name, value, type, checked } = e.target;
      const keys = name.split('.');

      if (keys.length === 2) {
          setLocalInfo(prev => ({
              ...prev,
              [keys[0]]: { ...prev[keys[0]], [keys[1]]: value }
          }));
      } else {
          setLocalInfo(prev => ({ ...prev, [name]: type === 'checkbox' ? checked : value }));
      }
    };

    const handleSave = async () => {
        setIsSaving(true);
        await updateCompanyInfo(localInfo);
        setIsSaving(false);
        showToast("Global settings saved!");
    };

    const handleDiscard = () => setLocalInfo(companyInfo);

    return (
        <div className="space-y-6">
            <div className="glass-card rounded-3xl overflow-hidden">
                <div className="p-6 md:p-8">
                  <h3 className="text-2xl font-bold mb-6">Company Identity</h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div><label className="text-xs font-bold uppercase text-stone-400">Website Name</label>
                      <input name="name" className="w-full p-3 border rounded-lg" value={localInfo.name} onChange={handleChange} /></div>
                      <div><label className="text-xs font-bold uppercase text-stone-400">Owner Name</label>
                      <input name="ownerName" className="w-full p-3 border rounded-lg" value={localInfo.ownerName} onChange={handleChange} /></div>
                      <div className="md:col-span-2"><label className="text-xs font-bold uppercase text-stone-400">Slogan / Tagline</label>
                      <input name="slogan" className="w-full p-3 border rounded-lg" value={localInfo.slogan} onChange={handleChange} /></div>
                  </div>
                </div>
                 <ActionButtons hasChanges={hasChanges} isSaving={isSaving} onSave={handleSave} onDiscard={handleDiscard} />
            </div>
            <div className="glass-card rounded-3xl overflow-hidden">
                <div className="p-6 md:p-8">
                  <h3 className="text-2xl font-bold mb-6">Contact & Social</h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div><label className="text-xs font-bold uppercase text-stone-400">Phone</label>
                      <input name="phone" className="w-full p-3 border rounded-lg" value={localInfo.phone} onChange={handleChange} /></div>
                      <div><label className="text-xs font-bold uppercase text-stone-400">Email</label>
                      <input name="email" className="w-full p-3 border rounded-lg" value={localInfo.email} onChange={handleChange} /></div>
                      <div><label className="text-xs font-bold uppercase text-stone-400">Location</label>
