                      <div><label className="text-xs font-bold uppercase text-stone-400">WhatsApp Link</label>
                      <input name="social.whatsapp" className="w-full p-3 border rounded-lg" value={localInfo.social.whatsapp} onChange={handleChange} /></div>
                       <div><label className="text-xs font-bold uppercase text-stone-400">Instagram Link</label>
                      <input name="social.instagram" className="w-full p-3 border rounded-lg" value={localInfo.social.instagram} onChange={handleChange} /></div>
                       <div><label className="text-xs font-bold uppercase text-stone-400">Facebook Link</label>
                      <input name="social.facebook" className="w-full p-3 border rounded-lg" value={localInfo.social.facebook} onChange={handleChange} /></div>
                  </div>
                </div>
                 <ActionButtons hasChanges={hasChanges} isSaving={isSaving} onSave={handleSave} onDiscard={handleDiscard} />
            </div>
            <div className="glass-card p-6 md:p-8 rounded-3xl">
              <h3 className="text-2xl font-bold mb-4 flex items-center gap-2"><Zap size={20}/> Animation Effects</h3>
              <div className="flex items-center justify-between">
                <p className="text-stone-600">Enable physics-based animations across the website.</p>
