                            <input className="w-full p-3 border rounded" value={localContent.home.welcome.title} onChange={(e) => handleChange('home.welcome.title', e.target.value)} />
                            <textarea rows={4} className="w-full p-3 border rounded" value={localContent.home.welcome.content} onChange={(e) => handleChange('home.welcome.content', e.target.value)} />
